import{_ as e,o as a,c as s,W as i}from"./chunks/framework.71c88ce2.js";const u=JSON.parse('{"title":"XSS","description":"","frontmatter":{},"headers":[],"relativePath":"browser/xss.md","filePath":"browser/xss.md","lastUpdated":1689679322000}'),t={name:"browser/xss.md"},r=i('<h1 id="xss" tabindex="-1">XSS <a class="header-anchor" href="#xss" aria-label="Permalink to &quot;XSS&quot;">​</a></h1><p>Cross-Site Scripting（跨站脚本攻击）简称 XSS，是一种代码注入攻击。攻击者通过在目标网站上注入恶意脚本，使之在用户的浏览器上运行。利用这些恶意脚本，攻击者可获取用户的敏感信息如 Cookie、SessionID 等，进而危害数据安全。</p><p>XSS 攻击是页面被注入了恶意的代码。</p><ul><li>通常页面中包含的用户输入内容都在固定的容器或者属性内，以文本的形式展示</li><li>攻击者利用这些页面的用户输入片段，拼接特殊格式的字符串，突破原有位置的限制，形成了代码片段。</li><li>攻击者通过在目标网站上注入脚本，使之在用户浏览器上运行，从而引发潜在风险。</li></ul><h2 id="注入的方式" tabindex="-1">注入的方式 <a class="header-anchor" href="#注入的方式" aria-label="Permalink to &quot;注入的方式&quot;">​</a></h2><ul><li>在 HTML 中内嵌的文本中，恶意内容以 script 标签形成注入。</li><li>在内联的 javascript 中，拼接的数据突破了原本的限制（字符串，变量，方法名等）。</li><li>在标签属性中，恶意内容包含引号，从而突破属性值的限制，注入其他属性或者标签</li><li>在标签的 href、src等属性中，包含 javascript: 等可执行代码。</li><li>在 onload、 onerror、 onclick 等事件中，注入不受控制代码。</li><li>在 style 属性和标签中，包含了类似 background-image:url(&quot;javascript:...&quot;); 的代码（新版本浏览器已经可以防范）。</li><li>在 style 属性和标签中，包含类似 expression(...) 的 CSS 表达式代码（新版本浏览器已经可以防范）。</li></ul>',6),l=[r];function o(c,n,_,d,p,S){return a(),s("div",null,l)}const m=e(t,[["render",o]]);export{u as __pageData,m as default};
